import{_ as l,M as t,p as i,q as o,R as e,t as a,N as r,a1 as g}from"./framework-822ca1a4.js";const s={},c=e("h1",{id:"每周一词-engage",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#每周一词-engage","aria-hidden":"true"},"#"),a(" 每周一词-Engage")],-1),d=e("p",null,"2023 年 5 月 2 日 15:03:19",-1),h={href:"https://www.bbc.co.uk/learningenglish/chinese/features/english-in-a-minute/ep-230421",target:"_blank",rel:"noopener noreferrer"},u=g('<h2 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h2><p>动词“engage”的意思是都与“和他人互动”有关。比如，动词“engage”可以表示“使（某人）感兴趣”或“聘用”；在正式语境中，动词短语“engage in”指“参与（活动）”。</p><h2 id="用法总结" tabindex="-1"><a class="header-anchor" href="#用法总结" aria-hidden="true">#</a> 用法总结</h2><ol><li>用“engage”指“吸引住（某人），使（某人）感兴趣”。</li></ol><ul><li>You really know how to engage people -- you&#39;re really interesting!</li><li>As an experienced presenter, he&#39;s very good at engaging the audience.</li></ul><ol start="2"><li>用“engage”表示“雇佣，聘用”。</li></ol><ul><li>We&#39;ve engage someone to help us with our accounts.</li><li>We had to engage a team of 20 cleaners to clean the building.</li></ul><ol start="3"><li>用动词短语“engage in”表示“参与，参加（活动）”，这是一个正式用语。</li></ol><ul><li>She liked to engage in extreme sports.</li><li>He denies engaging in any criminal activity.</li></ul><ol start="4"><li>用动词短语“got engaged”表示“订婚”。</li></ol><ul><li>He&#39;s just got engaged -- he&#39;s really excited.</li><li>She is getting engaged to her former colleague.</li></ul>',11);function _(p,f){const n=t("ExternalLinkIcon");return i(),o("div",null,[c,d,e("p",null,[e("a",h,[a("BBC"),r(n)])]),u])}const x=l(s,[["render",_],["__file","word-engage.html.vue"]]);export{x as default};
